import axios from 'axios';

const BASE_URL = 'http://localhost:5000/api/';
console.log(JSON.parse(JSON.parse(localStorage.getItem("persist:root"))?.user).currentUser)
const TOKEN = JSON.parse(JSON.parse(localStorage.getItem("persist:root"))?.user).currentUser
    ? JSON.parse(JSON.parse(localStorage.getItem("persist:root"))?.user).currentUser.accessToken
    : null;
// console.log(TOKEN);
// const TOKEN = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjYzYTg1MDUzMjU3NTljNDI4ZmIwNzExNyIsImlzQWRtaW4iOnRydWUsImlhdCI6MTY3MjE2MjcxNSwiZXhwIjoxNjcyNDIxOTE1fQ.xd5uXpjQQUi-FhtP1y_sEyXSnTACCIZwpuY94HaDvhI"
export const publicRequest = axios.create({
    baseURL: BASE_URL
});

export const userRequest = axios.create({
    baseURL: BASE_URL,
    headers: {token: `Bearer ${TOKEN}`},
});
